# server.py
from mcp.server.fastmcp import FastMCP

mcp = FastMCP("notes")
notes: list[str] = []

@mcp.tool()
def add_note(text: str) -> str:
    """Save a note for the user."""
    notes.append(text)
    return f"Saved note #{len(notes)}"

@mcp.tool()
def list_notes() -> str:
    """List all saved notes."""
    if not notes:
        return "No notes yet."
    return "\n".join(f"{i+1}. {n}" for i, n in enumerate(notes))

