// server.js
import { McpServer } from "@modelcontextprotocol/sdk/server/mcp.js";
import { z } from "zod";

export const server = new McpServer({ name: "notes", version: "1.0.0" });
const notes = [];

server.tool("add_note", "Save a note for the user",
  { text: z.string().describe("The note text") },
  async ({ text }) => {
    notes.push(text);
    return { content: [{ type: "text", text: `Saved note #${notes.length}` }] };
  });

server.tool("list_notes", "List all saved notes", {}, async () => ({
  content: [{
    type: "text",
    text: notes.length
      ? notes.map((n, i) => `${i + 1}. ${n}`).join("\n")
      : "No notes yet.",
  }],
}));

