import { Client } from "@modelcontextprotocol/sdk/client/index.js";
import { StdioClientTransport } from "@modelcontextprotocol/sdk/client/stdio.js";

const transport = new StdioClientTransport({
  command: "node",
  args: ["server.js"],
});
const client = new Client({ name: "notes-client", version: "1.0.0" });
await client.connect(transport);

const { tools } = await client.listTools();
for (const t of tools) console.log(`${t.name}: ${t.description}`);

await client.close();

// after client.connect(), before client.close():
let result = await client.callTool({
  name: "add_note",
  arguments: { text: "MCP is just JSON-RPC with a handshake" },
});
console.log(result.content[0].text);

result = await client.callTool({ name: "list_notes", arguments: {} });
console.log(result.content[0].text);

// llm_loop.js
import Anthropic from "@anthropic-ai/sdk";
import { Client } from "@modelcontextprotocol/sdk/client/index.js";
import { StdioClientTransport } from "@modelcontextprotocol/sdk/client/stdio.js";

const llm = new Anthropic();
const client = new Client({ name: "llm-client", version: "1.0.0" });
await client.connect(
  new StdioClientTransport({ command: "node", args: ["server.js"] }));

const tools = (await client.listTools()).tools.map((t) => ({
  name: t.name, description: t.description, input_schema: t.inputSchema,
}));
const messages = [{ role: "user",
  content: "Save a note saying 'ship it', then list my notes." }];

while (true) {
  const resp = await llm.messages.create({
    model: "claude-sonnet-4-6", max_tokens: 1024, tools, messages,
  });
  if (resp.stop_reason !== "tool_use") {
    console.log(resp.content[0].text);
    break;
  }
  messages.push({ role: "assistant", content: resp.content });
  const results = [];
  for (const block of resp.content) {
    if (block.type !== "tool_use") continue;
    const out = await client.callTool({ name: block.name, arguments: block.input });
    results.push({ type: "tool_result", tool_use_id: block.id,
                   content: out.content[0].text });
  }
  messages.push({ role: "user", content: results });
}
await client.close();

